# scripts/check_vulnerabilities.py
# Run on every CI push and on a nightly schedule
import subprocess
import json
import sys

def run_audit() -> list[dict]:
    result = subprocess.run(
        ["pip-audit", "--output", "json", "-r", "requirements.txt"],
        capture_output=True,
        text=True,
    )
    data = json.loads(result.stdout)
    return data.get("vulnerabilities", [])

def severity_label(cvss: float) -> str:
    if cvss >= 9.0:
        return "CRITICAL"
    elif cvss >= 7.0:
        return "HIGH"
    elif cvss >= 4.0:
        return "MEDIUM"
    return "LOW"

def main():
    vulns = run_audit()
    critical = [v for v in vulns if v.get("fix_versions") and float(v.get("aliases", [{}])[0].get("cvss_v3", {}).get("baseScore", 0)) >= 9.0]

    if critical:
        print(f"EMERGENCY: {len(critical)} critical vulnerabilities found")
        for v in critical:
            print(f"  {v['id']} in {v['name']}=={v['version']}")
        sys.exit(1)  # Fail CI, trigger PagerDuty alert
    else:
        print(f"{len(vulns)} non-critical findings, continuing.")

if __name__ == "__main__":
    main()
